1	/**
2	 * FleetGuard — Firestore collection name constants + runtime safety assertion
3	 *
4	 * Every service file MUST import collection names from here.
5	 * Never write a bare "fg_*" string literal directly in a service.
6	 * Never write a non-fg_* string under any circumstances (safety rule S1/S3).
7	 */
8	
9	// ── Collection constants ────────────────────────────────────────────────────
10	
11	export const FG_ORGANISATIONS       = "fg_organisations"       as const;
12	export const FG_WAREHOUSES          = "fg_warehouses"          as const;
13	export const FG_USERS               = "fg_users"               as const;
14	export const FG_CONTRACTORS         = "fg_contractors"         as const;
15	export const FG_DRIVERS             = "fg_drivers"             as const;
16	export const FG_DRIVER_BACKGROUND   = "fg_driver_background"   as const;
17	export const FG_VEHICLES            = "fg_vehicles"            as const;
18	export const FG_GATE_EVENTS         = "fg_gate_events"         as const;
19	export const FG_INBOUND_ENTRIES     = "fg_inbound_entries"     as const;
20	export const FG_VISITOR_ENTRIES     = "fg_visitor_entries"     as const;
21	export const FG_TRIPS               = "fg_trips"               as const;
22	export const FG_TRIP_STOPS          = "fg_trip_stops"          as const; // subcollection
23	export const FG_COMPLIANCE_CHECKS   = "fg_compliance_checks"   as const;
24	export const FG_ALERTS              = "fg_alerts"              as const;
25	export const FG_INCIDENTS           = "fg_incidents"           as const;
26	export const FG_AUDIT_EVENTS        = "fg_audit_events"        as const;
27	export const FG_BG_SCREENING        = "fg_bg_screening_requests" as const;
28	
29	// ── Runtime safety assertion ─────────────────────────────────────────────────
30	
31	/**
32	 * Throws if the given collection path does not start with "fg_".
33	 * Call this at the top of every service function that references a collection.
34	 *
35	 * @example
36	 *   const col = assertFgPath(FG_DRIVERS); // returns "fg_drivers"
37	 *   const colRef = collection(db, col);
38	 */
39	export function assertFgPath(path: string): string {
40	  if (!path.startsWith("fg_")) {
41	    throw new Error(
42	      `REFUSED: "${path}" is not an fg_* Firestore path. ` +
43	      "FleetGuard safety rule S1/S3 — all collections must be prefixed fg_."
44	    );
45	  }
46	  return path;
47	}
48	
49	// ── Type helpers ─────────────────────────────────────────────────────────────
50	
51	export type FgCollection =
52	  | typeof FG_ORGANISATIONS
53	  | typeof FG_WAREHOUSES
54	  | typeof FG_USERS
55	  | typeof FG_CONTRACTORS
56	  | typeof FG_DRIVERS
57	  | typeof FG_DRIVER_BACKGROUND
58	  | typeof FG_VEHICLES
59	  | typeof FG_GATE_EVENTS
60	  | typeof FG_INBOUND_ENTRIES
61	  | typeof FG_VISITOR_ENTRIES
62	  | typeof FG_TRIPS
63	  | typeof FG_TRIP_STOPS
64	  | typeof FG_COMPLIANCE_CHECKS
65	  | typeof FG_ALERTS
66	  | typeof FG_INCIDENTS
67	  | typeof FG_AUDIT_EVENTS
68	  | typeof FG_BG_SCREENING;
