3	 *
4	 * IMPORT BOUNDARY (brief §14 rule 12 + safety rule S8):
5	 *   This file may ONLY be imported by files under /app/_services/.
6	 *   Pages, components, hooks, and API routes must never import this directly.
7	 *
8	 * If you are a service author: import { db, auth, storage } from "../_lib/firebase"
9	 */
10	
11	import { initializeApp, getApps, getApp } from "firebase/app";
12	import { getAuth } from "firebase/auth";
13	import { getFirestore } from "firebase/firestore";
14	import { getStorage } from "firebase/storage";
15	
16	const firebaseConfig = {
17	  apiKey:            process.env.NEXT_PUBLIC_FIREBASE_API_KEY!,
18	  authDomain:        process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN!,
19	  projectId:         process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID!,
20	  storageBucket:     process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET!,
21	  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID!,
22	  appId:             process.env.NEXT_PUBLIC_FIREBASE_APP_ID!,
23	};
24	
25	// Singleton — safe for hot-reload in Next.js dev mode
26	const app = getApps().length === 0 ? initializeApp(firebaseConfig) : getApp();
27	
28	export const auth    = getAuth(app);
29	export const db      = getFirestore(app);
30	export const storage = getStorage(app);
