/**
 * FleetGuard — User service (DAL)
 * Reads/writes to fg_users collection only.
 */

import {
  doc, getDoc, setDoc, updateDoc, collection, query,
  where, getDocs, serverTimestamp,
} from "firebase/firestore";
import { db } from "../_lib/firebase";
import { assertFgPath, FG_USERS } from "../_lib/fg-paths";
import type { UserRole } from "../_lib/types";

export interface FgUser {
  uid: string;
  email: string;
  displayName: string;
  role: UserRole;
  warehouseId: string;
  orgId: string;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
}

type FgUserDoc = Omit<FgUser, "createdAt" | "updatedAt"> & {
  createdAt: { toDate(): Date } | null;
  updatedAt: { toDate(): Date } | null;
};

function toFgUser(id: string, data: FgUserDoc): FgUser {
  return {
    ...data,
    uid: id,
    createdAt: data.createdAt?.toDate() ?? new Date(),
    updatedAt: data.updatedAt?.toDate() ?? new Date(),
  };
}

export async function getUserById(uid: string): Promise<FgUser | null> {
  assertFgPath(FG_USERS);
  const snap = await getDoc(doc(db, FG_USERS, uid));
  if (!snap.exists()) return null;
  return toFgUser(snap.id, snap.data() as FgUserDoc);
}

export async function getUsersByWarehouse(warehouseId: string): Promise<FgUser[]> {
  assertFgPath(FG_USERS);
  const q = query(
    collection(db, FG_USERS),
    where("warehouseId", "==", warehouseId),
    where("isActive", "==", true)
  );
  const snap = await getDocs(q);
  return snap.docs.map((d) => toFgUser(d.id, d.data() as FgUserDoc));
}

export async function createUser(
  uid: string,
  data: Omit<FgUser, "uid" | "createdAt" | "updatedAt">
): Promise<void> {
  assertFgPath(FG_USERS);
  await setDoc(doc(db, FG_USERS, uid), {
    ...data,
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp(),
  });
}

export async function updateUserWarehouse(
  uid: string,
  warehouseId: string
): Promise<void> {
  assertFgPath(FG_USERS);
  await updateDoc(doc(db, FG_USERS, uid), {
    warehouseId,
    updatedAt: serverTimestamp(),
  });
}
